// src/components/Sources.js
import React, { useState } from 'react';

const Sources = () => {
  const [rssLinks, setRssLinks] = useState([]);
  const [rssInput, setRssInput] = useState('');
  const [pdfs, setPdfs] = useState([]);

  const handleAddRSS = () => {
    if (rssInput.trim()) {
      setRssLinks(prev => [...prev, rssInput.trim()]);
      setRssInput('');
    }
  };

  const handlePDFUpload = (e) => {
    const files = Array.from(e.target.files);
    setPdfs(prev => [...prev, ...files.map(file => file.name)]);
  };

  return (
    <div>
      <h2 className="text-xl font-bold mb-4">Sources</h2>

      <div className="mb-6">
        <h3 className="font-semibold mb-2">RSS Feeds</h3>
        <div className="flex gap-2 mb-2">
          <input
            type="text"
            className="border px-2 py-1 w-full"
            placeholder="Add RSS URL"
            value={rssInput}
            onChange={e => setRssInput(e.target.value)}
          />
          <button onClick={handleAddRSS} className="bg-blue-500 text-white px-3 py-1 rounded">Add</button>
        </div>
        <ul className="text-sm text-gray-700 list-disc list-inside">
          {rssLinks.map((link, i) => <li key={i}>{link}</li>)}
        </ul>
      </div>

      <div>
        <h3 className="font-semibold mb-2">Upload PDFs</h3>
        <input type="file" accept="application/pdf" multiple onChange={handlePDFUpload} />
        <ul className="text-sm mt-2 text-gray-700 list-disc list-inside">
          {pdfs.map((file, i) => <li key={i}>{file}</li>)}
        </ul>
      </div>
    </div>
  );
};

export default Sources;
